import{c as d,Z as a,Q as l,j as u,g as t,n as o,o as n,m as s,av as p}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"Arm Scoped autonomy","description":"Mint a Scoped session on the dashboard so HavenBot can buy and sell for you without a per-trade prompt.","frontmatter":{"title":"Arm Scoped autonomy","description":"Mint a Scoped session on the dashboard so HavenBot can buy and sell for you without a per-trade prompt."},"headers":[],"relativePath":"guide/agent/set-tier.md","filePath":"guide/agent/set-tier.md","lastUpdated":1780218602000}'),c={name:"guide/agent/set-tier.md"};function h(g,e,m,y,b,f){const r=a("TaskMeta"),i=a("ExpectedResult");return l(),u("div",null,[e[1]||(e[1]=t("h1",{id:"arm-scoped-autonomy",tabindex:"-1"},[o("Arm Scoped autonomy "),t("a",{class:"header-anchor",href:"#arm-scoped-autonomy","aria-label":'Permalink to "Arm Scoped autonomy"'},"​")],-1)),n(r,{time:"~3 min",role:"Any signed-in user",needs:"Signed in with your passkey"}),e[2]||(e[2]=s('<blockquote><p><strong>What you&#39;ll do:</strong> mint a <strong>Scoped session</strong> on the dashboard — the one step that lets HavenBot buy and sell on your behalf without asking you to confirm each trade.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>Be signed in with your passkey. You decide how much rope the agent gets, and you can change or revoke it anytime.</p></div><p>This is <strong>the enabling step</strong> for autonomous trading. Once a Scoped session is live, the next page (<a href="/guide/agent/autonomous">H4 · Buy &amp; sell autonomously</a>) shows HavenBot executing real trades from plain-language requests — no confirmation modal per trade.</p><h2 id="how-much-rope-you-can-give-the-agent" tabindex="-1">How much rope you can give the agent <a class="header-anchor" href="#how-much-rope-you-can-give-the-agent" aria-label="Permalink to &quot;How much rope you can give the agent&quot;">​</a></h2><p>You pick one of four tiers:</p><ul><li><strong>Advisory</strong> — read-only. Every write needs a fresh passkey signature.</li><li><strong>Confirm per action</strong> — the agent proposes; you confirm each write.</li><li><strong>Policy-bound</strong> — the agent writes within an allowlist plus spend caps.</li><li><strong>Scoped autonomy</strong> — autonomous buys &amp; sells within a <strong>per-trade cap</strong> and a <strong>time limit (TTL)</strong>, with <strong>no per-trade prompt</strong>. This is the one that unlocks hands-off trading.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Go to <code>/agent/policy/transition</code> (you can also ask HavenBot to <em>&quot;open my agent settings&quot;</em>).</li><li><strong>Pick the <code>Scoped autonomy</code> tier</strong> directly — there&#39;s no ladder to climb; any tier is one confirming tap away.</li><li>Set your <strong>per-trade cap</strong> (the maximum mhUSDC the agent can spend on a single trade — defaults to $100) and a <strong>TTL</strong> (how long the session stays valid).</li><li>Click <strong>Confirm transition</strong>, then <strong>approve with your passkey</strong>.</li><li>A <strong>session-key reveal modal</strong> opens. It mints a short-lived signing key <strong>on your device</strong> and surfaces it. For HavenBot in this same browser, you&#39;re done — the session is already active. (If you also run the MCP server, this is the key you&#39;ll hand to the broker — see <a href="/guide/mcp/arm-scoped">M1 · Arm Scoped autonomy on the dashboard</a>.)</li></ol><div class="info custom-block"><p class="custom-block-title">The Scoped key is minted on your device</p><p>The session key is generated <strong>client-side</strong> and is <strong>never sent over the wire</strong>. HavenBot gets time-boxed, capped signing rights — not your passkey.</p></div><div class="tip custom-block"><p class="custom-block-title">You can revoke it anytime</p><p>The same page shows a <strong>Revoke</strong> zone once a session is live, and you can lock the agent down instantly by asking HavenBot to <em>&quot;pause my agent&quot;</em>. Revoking or pausing blocks every write at once.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',12)),n(i,null,{default:p(()=>[...e[0]||(e[0]=[o(" After your passkey confirms, a ",-1),t("strong",null,"live Scoped session",-1),o(" exists — shown by the session banner and the revoke zone on the policy page. HavenBot can now buy and sell up to your per-trade cap, until the TTL expires, without prompting you each time. ",-1)])]),_:1}),e[3]||(e[3]=s('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Scoped modal didn&#39;t mint a key</td><td>Cancel and reopen the modal; the key is generated locally, so retry on-device.</td></tr><tr><td>Want to lock the agent down fast</td><td>Ask HavenBot to <em>&quot;pause my agent&quot;</em>, or hit <strong>Revoke</strong> on the policy page — both block every write instantly.</td></tr><tr><td>Want to resume after pausing</td><td>Pick a tier again on the dashboard; your passkey installs a fresh session.</td></tr><tr><td>The cap or TTL won&#39;t accept your value</td><td>The per-trade cap must be at least <strong>$1 mhUSDC</strong> and the TTL must be one of the offered options.</td></tr></tbody></table><p>→ Next: <a href="/guide/agent/autonomous">Buy &amp; sell autonomously</a></p>',3))])}const w=d(c,[["render",h]]);export{v as __pageData,w as default};
